def counting_triangles_in_grid_n_on_k(n, k):
    if k > n:
        n, k = k, n
        print("You entered a number less than the value of the smaller side\n"
              "of the grid into the value of the larger side of the grid, \n"
              "so these values were rearranged")
    sum_triangles = 0
    i = 0
    while i < k:
        #The sum of the triangles whose legs lie on the borders of the grid
        sum_triangles += 4 * (n - i) * (k - i)
        i += 1
    i = 0
    while i < k and i < (2*n - 1)/4:
        # The sum of triangles whose hypotenuse lies on the border of the grid and it's vertical
        sum_triangles += 2 * (k - i) * (2 * n - 1 - 4 * i)
        i += 1
    i = 0
    while i < (2*k - 1)/4:
        # The sum of triangles whose hypotenuse lies on the border of the grid and it's horizontal
        sum_triangles += 2 * (n - i) * (2 * k - 1 - 4 * i)
        i += 1
    return sum_triangles
for n in range(1, 11):
    print(n, end=" ")
    for k in range(1, 11):
        if n > k: print(counting_triangles_in_grid_n_on_k(n, k), end=", ")
        if n == k: print(counting_triangles_in_grid_n_on_k(n, k))

